import{_ as e,o as a,c as i,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"15A. Climate Change Mitigation And Sustainability","description":"","frontmatter":{"title":"15A. Climate Change Mitigation And Sustainability","eba":"Medical Specialists 2022-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/consultation-disputes/15A-climate-change-mitigation-and-sustainability.md","filePath":"ebas/medical-specialists/consultation-disputes/15A-climate-change-mitigation-and-sustainability.md"}'),s={name:"ebas/medical-specialists/consultation-disputes/15A-climate-change-mitigation-and-sustainability.md"};function o(r,t,l,c,p,g){return a(),i("div",null,[...t[0]||(t[0]=[n('<h1 id="_15a-climate-change-mitigation-and-sustainability" tabindex="-1">15A. Climate Change Mitigation And Sustainability <a class="header-anchor" href="#_15a-climate-change-mitigation-and-sustainability" aria-label="Permalink to &quot;15A. Climate Change Mitigation And Sustainability&quot;">​</a></h1><p><strong>15A.1</strong> Acknowledgment</p><p>The parties acknowledge that:</p><p><strong>(a)</strong> the climate is changing and this affects the health and wellbeing of Victorians:</p><p><strong>(b)</strong> Health Services use significant amounts of energy and water and generate large volumes of waste;</p><p><strong>(c)</strong> the Climate Change Act 2017 has a long-term emissions reduction target for Victoria of net zero greenhouse gas emissions by the year 2050 with a series of interim targets to achieve that goal; and</p><p><strong>(d)</strong> Doctors and Health Services have a role to play to support the achievement of that target, which includes through discussion, information sharing and cooperation.</p><p><strong>15A.2</strong> Continuous improvement</p><p><strong>(a)</strong> Doctors and Employers support continuous improvement to improve environmental sustainability including:</p><p><strong>(i)</strong> At an industry level through the Best Practice Employment Commitment term at <a href="/eba/ebas/medical-specialists/union-matters/63-best-practice-employment-commitment-committee.html">clause 63</a>;</p><p><strong>(ii)</strong> At a local workplace level through:</p><p>A. the WIC (see subclause 62.10) where it is in operation; and/or</p><p>B. a local body established for the purpose of consulting over environmental sustainability and climate change (however described).</p><p><strong>(b)</strong> Doctors and Employers support the development of local processes to:</p><p><strong>(i)</strong> integrate climate and environmental considerations into the evidence-based decision-making process;</p><p><strong>(ii)</strong> engage with Doctors to consult over matters of environmental sustainability including possible mitigants such as:</p><p>A. recycling and waste reduction;</p><p>B. better use of technology;</p><p>C. healthy sustainable buildings, infrastructure and materials; and</p><p>D. the delivery of health services;</p><p><strong>(iii)</strong> implement change at the workplace level to achieve environmental sustainability objectives including through local action plans as Health Services seek to move to 100% renewable energy by 2025.</p><p><strong>15A.3</strong> Education</p><p><strong>(a)</strong> It is acknowledged that education concerning to climate related health topics may be directly relevant to a Doctor’s role within the meaning of <a href="/eba/ebas/medical-specialists/leave/59-continuing-medical-education-leave.html">clause 59</a> (Continuing Medical Education.</p><p><strong>(b)</strong> The Health Service will encourage and support the inclusion of climate- related health topics as part of education provided to Doctors.</p><p><strong>15A.4</strong> Discussions with Association</p><p><strong>(a)</strong> Upon request, a Health Service will meet the Ambassador or other representative of the Association to discuss the sustainability report of the Health Service.</p><p>MATTERS</p><p>Plain language terms: climate, sustainability.</p>',28)])])}const d=e(s,[["render",o]]);export{m as __pageData,d as default};
